using UnityEngine;
using System.Collections.Generic;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int maxHealth = 100;
    public int currency = 1000;
    public int damage = 10;
    
    private Dictionary<string, int> shopItems = new Dictionary<string, int>();
    
    void Start()
    {
        InitializeShop();
    }
    
    void InitializeShop()
    {
        shopItems.Add("HealthPotion", 50);
        shopItems.Add("DamageUpgrade", 200);
        shopItems.Add("ArmorUpgrade", 300);
    }
    
    public void TakeDamage(int damageAmount)
    {
        health -= damageAmount;
        if (health < 0) health = 0;
    }
    
    public bool CanAfford(string item)
    {
        if (shopItems.ContainsKey(item))
        {
            return currency >= shopItems[item];
        }
        return false;
    }
    
    public bool PurchaseItem(string item)
    {
        if (CanAfford(item))
        {
            currency -= shopItems[item];
            
            switch (item)
            {
                case "HealthPotion":
                    health = Mathf.Min(maxHealth, health + 50);
                    break;
                case "DamageUpgrade":
                    damage += 5;
                    break;
                case "ArmorUpgrade":
                    maxHealth += 20;
                    health = maxHealth;
                    break;
            }
            return true;
        }
        return false;
    }
    
    public int CalculateDamage(int baseDamage, int enemyLevel)
    {
        return Mathf.Max(1, baseDamage + (enemyLevel * 2));
    }
    
    public int CalculatePrice(int basePrice, int itemLevel)
    {
        return Mathf.Max(1, basePrice + (itemLevel * 10));
    }
}

public class GameManager : MonoBehaviour
{
    public PlayerStats playerStats;
    
    void Start()
    {
        if (playerStats == null)
        {
            playerStats = FindObjectOfType<PlayerStats>();
        }
    }
    
    public void PlayerAttack(int enemyLevel)
    {
        int calculatedDamage = playerStats.CalculateDamage(playerStats.damage, enemyLevel);
        Debug.Log("Player dealt " + calculatedDamage + " damage");
    }
    
    public void BuyItem(string item)
    {
        if (playerStats.PurchaseItem(item))
        {
            Debug.Log("Purchased " + item);
        }
        else
        {
            Debug.Log("Cannot afford " + item);
        }
    }
}